53→export function createCopyAction(
54→  options: CreateCopyActionOptions,
55→  showHUD: ShowHUD,
56→): DropdownAction {
57→  return {
58→    label: options.title ?? 'Copy',
59→    shortcut: options.shortcut,
60→    onClick: () => {
61→      copyToClipboard(options.content).catch(() => {});
62→      showHUD({
63→        icon: options.hudIcon ?? <CopyHUDIcon />,
64→        title: options.hudTitle ?? 'Copied to Clipboard',
65→      });
66→      options.onCopy?.();
67→    },
68→  };
