116→const PIN_STATE_KEY = 'clipboard-pins';
117→const DELETED_KEY = 'clipboard-deleted';
118→
119→function loadInitialEntries(): ClipboardEntry[] {
120→  const pinState = storageGet(PIN_STATE_KEY, isBooleanRecord) ?? {};
121→  const deleted = new Set(storageGet(DELETED_KEY, isStringArray) ?? []);
122→  return MOCK_CLIPBOARD_ENTRIES.filter(e => !deleted.has(e.id)).map(e => ({
123→    ...e,
124→    pinned: e.id in pinState ? pinState[e.id]! : e.pinned,
125→  }));
126→}
127→
128→function saveEntryState(entries: ClipboardEntry[]) {
129→  const pinState: Record<string, boolean> = {};
130→  for (const e of entries) {
131→    pinState[e.id] = e.pinned;
132→  }
133→  storageSet(PIN_STATE_KEY, pinState);
134→
135→  const allIds = new Set(MOCK_CLIPBOARD_ENTRIES.map(e => e.id));
136→  const currentIds = new Set(entries.map(e => e.id));
137→  const deleted = [...allIds].filter(id => !currentIds.has(id));
138→  storageSet(DELETED_KEY, deleted);
139→}
