487→                    <div className="emoji-picker__grid">
488→                      {section.emojis.map(emoji => {
489→                        const idx = globalIndex++;
490→                        const isActive = idx === activeIndex;
491→                        return (
492→                          <div
493→                            key={`${section.title}-${emoji.char}`}
494→                            id={`emoji-item-${idx}`}
495→                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
496→                            role="option"
497→                            aria-selected={isActive}
498→                            aria-label={emoji.name}
499→                            data-emoji-index={idx}
500→                            onClick={() => {
