502→                              handleCopyEmoji(emoji);
503→                            }}
504→                          >
505→                            {emoji.char}
506→                          </div>
507→                        );
508→                      })}
509→                    </div>
510→                  </div>
511→                ));
512→              })()}
513→            </div>
514→          )}
