519→        actions={[
520→          {
521→            label: selectedEmoji ? `Copy ${selectedEmoji.char}` : 'Copy Emoji',
522→            shortcut: <Kbd keys={['↵']} />,
523→          },
524→          {
525→            label: 'Actions',
526→            shortcut: (
527→              <Kbd
528→                keys={[
529→                  '⌘',
530→                  'K',
531→                ]}
532→              />
533→            ),
534→            onClick: toggleActions,
535→          },
536→        ]}
537→        dropdownOpen={actionsOpen}
538→        dropdownSections={dropdownSections}
539→        onDropdownClose={closeActions}
540→      />
541→      <HUDContainer items={hudItems} />
